// Claude.ai Response Formatter für PGVector Results
const { vectorResults, query, tool } = $input.first().json;

console.log('Formatting response for Claude.ai:', { tool, query });

// Claude.ai-kompatible Response formatieren
if (tool === 'search_memory') {
    const results = vectorResults || [];

    if (results.length === 0) {
        return [{
            json: {
                content: [{
                    type: "text",
                    text: `🔍 **Memory Search: "${query}"**\n\n❌ No documents found matching your query.\n\nTry:\n• Different keywords\n• Broader search terms\n• Check if documents are stored in the database`
                }],
                isError: false
            }
        }];
    }

    let responseText = `🔍 **Memory Search Results for: "${query}"**\n\n`;
    responseText += `Found ${results.length} relevant document(s):\n\n`;

    results.forEach((doc, index) => {
        const content = doc.pageContent || doc.content || 'No content';
        const metadata = doc.metadata || {};
        const similarity = metadata.similarity || 'Unknown';

        responseText += `**${index + 1}. Document**\n`;
        responseText += `📄 Content: ${content.substring(0, 200)}${content.length > 200 ? '...' : ''}\n`;
        responseText += `📊 Relevance: ${similarity}\n`;
        responseText += `🏷️ Source: ${metadata.source || 'Unknown'}\n\n`;
    });

    responseText += `\n✅ Search completed successfully. Found ${results.length} relevant documents.`;

    return [{
        json: {
            content: [{
                type: "text",
                text: responseText
            }],
            isError: false
        }
    }];
}

if (tool === 'store_document') {
    const stored = vectorResults || {};

    return [{
        json: {
            content: [{
                type: "text",
                text: `✅ **Document Successfully Stored**\n\n` +
                      `📄 **Content Preview:** ${query?.substring(0, 150)}${query?.length > 150 ? '...' : ''}\n\n` +
                      `🎯 **Vector Embedding:** Generated and stored in pgvector database\n` +
                      `🔢 **Document ID:** ${stored.id || Date.now()}\n` +
                      `📅 **Timestamp:** ${new Date().toLocaleString()}\n\n` +
                      `The document has been processed and indexed for future searches. You can now find it using the 'search_memory' tool.`
            }],
            isError: false
        }
    }];
}

// Fallback für andere Tools
return [{
    json: {
        content: [{
            type: "text",
            text: `🔧 **Tool Executed: ${tool}**\n\nResults: ${JSON.stringify(vectorResults, null, 2)}`
        }],
        isError: false
    }
}];
